import { MakeLogicType, actions, connect, kea, key, path, props, reducers, selectors } from 'kea'

import { tagsModel } from '~/models/tagsModel'


export interface TagSelectLogicProps {
    logicKey: string
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface tagSelectLogicValues {
    tags: string[]; // tagsModel
    filteredTags: string[];
    search: string;
    showPopover: boolean;
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface tagSelectLogicActions {
    setSearch: (search: string) => {
        search: string;
    };
    setShowPopover: (visible: boolean) => {
        visible: boolean;
    };
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface tagSelectLogicMeta {
    key: string;
    __keaTypeGenInternalSelectorTypes: {
        filteredTags: (tags: string[], search: string) => string[];
    };
}

export type tagSelectLogicType = MakeLogicType<tagSelectLogicValues, tagSelectLogicActions, TagSelectLogicProps, tagSelectLogicMeta>;

export const tagSelectLogic = kea<tagSelectLogicType>([
    props({} as TagSelectLogicProps),
    key((props) => props.logicKey),
    path((logicKey) => ['lib', 'components', 'tagSelectLogic', logicKey]),
    connect(() => ({
        values: [tagsModel, ['tags']],
    })),
    actions(() => ({
        setSearch: (search: string) => ({ search }),
        setShowPopover: (visible: boolean) => ({ visible }),
    })),
    reducers(() => ({
        search: [
            '',
            {
                setSearch: (_, { search }) => search,
                setShowPopover: (state, { visible }) => (visible ? state : ''), // Clear search when closing
            },
        ],
        showPopover: [
            false,
            {
                setShowPopover: (_, { visible }) => visible,
            },
        ],
    })),
    selectors(() => ({
        filteredTags: [
            (s) => [s.tags, s.search],
            (tags: string[], search: string) => {
                if (!search) {
                    return tags || []
                }
                return (tags || []).filter((tag) => tag.toLowerCase().includes(search.toLowerCase()))
            },
        ],
    })),
])
